    unsafe fn from_napi_value(
        env: ::napi::sys::napi_env,
        napi_val: ::napi::sys::napi_value,
    ) -> ::napi::Result<Self> {
        TypeConversionTransport::from_napi_value(env, napi_val).map(Box::new)
    }
